function ComoFunciona() {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => e.isIntersecting && setVisible(true), { threshold: 0.2 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);

  return (
    <section id="como-funciona" ref={ref} style={{ padding: "100px 24px", backgroundColor: "#fff" }}>
      <div style={{ maxWidth: 1100, margin: "0 auto" }}>
        <div style={{ textAlign: "center", marginBottom: 64 }}>
          <div style={{ fontFamily: "var(--font-lato)", fontSize: 12, fontWeight: 700, color: "#c4703b", letterSpacing: "2px", textTransform: "uppercase", marginBottom: 12 }}>
            Simple y claro
          </div>
          <h2 style={{ fontFamily: "var(--font-playfair)", fontSize: "clamp(32px, 4vw, 48px)", fontWeight: 700, color: "#2a2a2a", lineHeight: 1.15 }}>
            Así funciona
          </h2>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 32 }} className="steps-grid">
          {STEPS.map((step, i) => (
            <div
              key={step.number}
              style={{
                opacity: visible ? 1 : 0, transform: visible ? "translateY(0)" : "translateY(24px)",
                transition: `all 0.5s ease ${i * 0.12}s`,
              }}
            >
              <div style={{ fontFamily: "var(--font-playfair)", fontSize: 52, fontWeight: 700, color: "#e8f0e9", lineHeight: 1, marginBottom: 16 }}>
                {step.number}
              </div>
              <h3 style={{ fontFamily: "var(--font-playfair)", fontSize: 20, fontWeight: 700, color: "#2a2a2a", marginBottom: 10 }}>
                {step.title}
              </h3>
              <p style={{ fontFamily: "var(--font-lato)", fontSize: 14, color: "#6b6b6b", lineHeight: 1.65 }}>
                {step.description}
              </p>
            </div>
          ))}
        </div>

        <style>{`
          @media (max-width: 900px) { .steps-grid { grid-template-columns: 1fr 1fr !important; } }
          @media (max-width: 600px) { .steps-grid { grid-template-columns: 1fr !important; } }
        `}</style>
      </div>
    </section>
  );
}

