        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {FAQS.map((faq, i) => (
            <div key={i} style={{ backgroundColor: "#fff", borderRadius: 16, border: "1px solid #e8e4dc", overflow: "hidden" }}>
              <button
                onClick={() => setOpenIdx(openIdx === i ? null : i)}
                style={{
                  width: "100%", padding: "20px 24px", display: "flex",
                  justifyContent: "space-between", alignItems: "center",
                  background: "none", border: "none", cursor: "pointer", textAlign: "left",
                }}
              >
                <span style={{ fontFamily: "var(--font-lato)", fontSize: 15, fontWeight: 700, color: "#2a2a2a", paddingRight: 16 }}>
                  {faq.pregunta}
                </span>
                <span style={{ fontSize: 20, color: "#2d5a3d", transition: "transform 0.3s", transform: openIdx === i ? "rotate(45deg)" : "rotate(0deg)", flexShrink: 0 }}>
                  +
                </span>
              </button>
              {openIdx === i && (
                <div style={{ padding: "0 24px 20px", fontFamily: "var(--font-lato)", fontSize: 14, color: "#6b6b6b", lineHeight: 1.7, borderTop: "1px solid #e8e4dc", paddingTop: 16 }}>
                  {faq.respuesta}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

function Contacto() {
  return (
    <section id="contacto" style={{ padding: "100px 24px", backgroundColor: "#2d5a3d" }}>
      <div style={{ maxWidth: 760, margin: "0 auto", textAlign: "center" }}>
        <div style={{ fontSize: 48, marginBottom: 24 }}>🍲</div>
        <h2 style={{ fontFamily: "var(--font-playfair)", fontSize: "clamp(32px, 4vw, 52px)", fontWeight: 700, color: "#faf7f2", lineHeight: 1.15, marginBottom: 16 }}>
          Arrancá esta semana
        </h2>
        <p style={{ fontFamily: "var(--font-lato)", fontSize: 18, color: "rgba(250,247,242,0.75)", marginBottom: 40, lineHeight: 1.65 }}>
          Escribinos por WhatsApp. Te tomamos el pedido, cocinamos y te lo llevamos el domingo.
        </p>

        <div style={{ display: "inline-flex", flexDirection: "column", gap: 16, backgroundColor: "rgba(255,255,255,0.1)", borderRadius: 20, padding: "32px 48px", border: "1px solid rgba(255,255,255,0.15)", marginBottom: 32 }}>
          {[
            { emoji: "📍", text: `${SITE.coverage} — Delivery en zona` },
            { emoji: "🗓️", text: `Pedidos hasta ${SITE.order_cutoff}` },
            { emoji: "🚚", text: `Entrega ${SITE.delivery_days}` },
            { emoji: "⏱️", text: "Respondemos en menos de 2 horas" },
          ].map((item) => (
            <div key={item.text} style={{ display: "flex", alignItems: "center", gap: 12, justifyContent: "center" }}>
              <span style={{ fontSize: 20 }}>{item.emoji}</span>
              <span style={{ fontFamily: "var(--font-lato)", fontSize: 15, color: "#faf7f2" }}>{item.text}</span>
            </div>
          ))}
        </div>

        <a
          href={`https://wa.me/${SITE.whatsapp}?text=Hola!%20Quiero%20empezar%20con%20Prep.%20¿Podemos%20coordinar%3F`}
          style={{
            display: "inline-flex", alignItems: "center", gap: 12,
            backgroundColor: "#25D366", color: "#fff",
            padding: "18px 40px", borderRadius: 14,
            fontFamily: "var(--font-lato)", fontSize: 17, fontWeight: 700,
            textDecoration: "none", letterSpacing: "0.3px",
            boxShadow: "0 4px 24px rgba(37,211,102,0.35)",
            transition: "all 0.2s",
          }}
          onMouseEnter={(e) => {
            (e.target as HTMLElement).style.transform = "translateY(-3px)";
            (e.target as HTMLElement).style.boxShadow = "0 8px 32px rgba(37,211,102,0.45)";
          }}
          onMouseLeave={(e) => {
            (e.target as HTMLElement).style.transform = "translateY(0)";
            (e.target as HTMLElement).style.boxShadow = "0 4px 24px rgba(37,211,102,0.35)";
          }}
        >
          <span style={{ fontSize: 24 }}>💬</span>
          Escribir por WhatsApp →
        </a>
      </div>
    </section>
  );
}

function Footer() {
  return (
    <footer style={{ backgroundColor: "#1a1a1a", padding: "40px 24px 32px" }}>
      <div style={{ maxWidth: 1100, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 20 }}>
        <div>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 8 }}>
            <div style={{ width: 28, height: 28, borderRadius: 8, backgroundColor: "#2d5a3d", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14 }}>
              🍲
            </div>
            <span style={{ fontFamily: "var(--font-playfair)", fontSize: 18, fontWeight: 700, color: "#faf7f2" }}>
              {SITE.name}
            </span>
            <span style={{ fontFamily: "var(--font-lato)", fontSize: 11, color: "rgba(250,247,242,0.4)", borderLeft: "1px solid rgba(250,247,242,0.2)", paddingLeft: 10, marginLeft: 4 }}>
              {SITE.tagline}
            </span>
          </div>
          <p style={{ fontFamily: "var(--font-lato)", fontSize: 12, color: "rgba(250,247,242,0.4)" }}>
            © 2026 Prep. {SITE.coverage}, Paraguay.
          </p>
        </div>
        <div style={{ display: "flex", gap: 24 }}>
          {[
            { label: "Cómo funciona", href: "#como-funciona" },
            { label: "Menú", href: "#menu" },
            { label: "Planes", href: "#planes" },
            { label: "FAQ", href: "#faq" },
          ].map((link) => (
            <a
              key={link.label}
              href={link.href}
              style={{
                fontFamily: "var(--font-lato)", fontSize: 13,
                color: "rgba(250,247,242,0.5)", textDecoration: "none",
                transition: "color 0.2s",
              }}
              onMouseEnter={(e) => ((e.target as HTMLElement).style.color = "#faf7f2")}
              onMouseLeave={(e) => ((e.target as HTMLElement).style.color = "rgba(250,247,242,0.5)")}
            >
              {link.label}
            </a>
          ))}
        </div>
      </div>
    </footer>
  );
}

// ─── PAGE ─────────────────────────────────────────────────────────────────────

export default function Page() {
  const [weekData, setWeekData] = useState(DEFAULT_WEEK);
  const [showCatalog, setShowCatalog] = useState(false);

  // Fetch active week from API on mount
  useEffect(() => {
    fetch("/api/menu/week")
      .then((r) => r.ok ? r.json() : null)
      .then((data) => {
        if (data && data.label) setWeekData(data);
      })
      .catch(() => { /* silently use defaults */ });
  }, []);

  return (
    <main>
      <Navbar onCatalog={() => setShowCatalog(true)} />
      <FloatingWhatsApp />
      <Hero weekData={weekData} />
      <ComoFunciona />
      <MenuSection weekData={weekData} />
      <Planes />
      <ChefSection onCatalog={() => setShowCatalog(true)} />
      <FAQ />
      <Contacto />
      <Footer />
      {showCatalog && <CatalogModal onClose={() => setShowCatalog(false)} />}
    </main>
  );
}
"}

