              {link.label}
            </a>
          ))}
        </div>
      </div>
    </footer>
  );
}

// ─── PAGE ─────────────────────────────────────────────────────────────────────

export default function Page() {
  const [weekData, setWeekData] = useState(DEFAULT_WEEK);
  const [showCatalog, setShowCatalog] = useState(false);

  // Fetch active week from API on mount (fixes broken static reference)
  useEffect(() => {
    fetch("/api/menu/week")
      .then((r) => r.ok ? r.json() : null)
      .then((data) => {
        if (data && data.label) setWeekData(data);
      })
      .catch(() => { /* silently use defaults */ });
  }, []);

  return (
    <main>
      <Navbar onCatalog={() => setShowCatalog(true)} />
      <FloatingWhatsApp />
      <Hero weekData={weekData} />
      <ComoFunciona />
      <MenuSection weekData={weekData} />
      <Planes />
      <ChefSection onCatalog={() => setShowCatalog(true)} />
      <FAQ />
      <Contacto />
      <Footer />
      {showCatalog && <CatalogModal onClose={() => setShowCatalog(false)} />}
    </main>
  );
}
"}

